PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE ZCAR ( Z_PK INTEGER PRIMARY KEY, Z_ENT INTEGER, Z_OPT INTEGER, ZMILEAGE INTEGER, ZPURCHASEDATE TIMESTAMP, ZBRAND VARCHAR, ZMODELNAME VARCHAR, ZID BLOB );
CREATE TABLE ZFUELLOG ( Z_PK INTEGER PRIMARY KEY, Z_ENT INTEGER, Z_OPT INTEGER, ZMILEAGE INTEGER, ZCAR INTEGER, ZAMOUNT FLOAT, ZDATE TIMESTAMP, ZLITERS FLOAT, ZID BLOB );
CREATE TABLE ZMAINTENANCEITEMOPTION ( Z_PK INTEGER PRIMARY KEY, Z_ENT INTEGER, Z_OPT INTEGER, ZDANGERSTARTPERCENT INTEGER, ZISDEFAULT INTEGER, ZMILEAGEINTERVAL INTEGER, ZMONTHINTERVAL INTEGER, ZREMINDBYMILEAGE INTEGER, ZREMINDBYTIME INTEGER, ZWARNINGSTARTPERCENT INTEGER, ZCREATEDAT TIMESTAMP, ZNAME VARCHAR, ZID BLOB , ZCATALOGKEY VARCHAR);
CREATE TABLE Z_METADATA (Z_VERSION INTEGER PRIMARY KEY, Z_UUID VARCHAR(255), Z_PLIST BLOB);
CREATE TABLE Z_MODELCACHE (Z_CONTENT BLOB);
CREATE TABLE ACHANGE ( Z_PK INTEGER PRIMARY KEY, Z_ENT INTEGER, Z_OPT INTEGER, ZCHANGETYPE INTEGER, ZENTITY INTEGER, ZENTITYPK INTEGER, ZTRANSACTIONID INTEGER, ZCOLUMNS BLOB );
CREATE TABLE ATRANSACTION ( Z_PK INTEGER PRIMARY KEY, Z_ENT INTEGER, Z_OPT INTEGER, ZAUTHORTS INTEGER, ZBUNDLEIDTS INTEGER, ZCONTEXTNAMETS INTEGER, ZPROCESSIDTS INTEGER, ZTIMESTAMP FLOAT, ZAUTHOR VARCHAR, ZBUNDLEID VARCHAR, ZCONTEXTNAME VARCHAR, ZPROCESSID VARCHAR, ZQUERYGEN BLOB );
CREATE TABLE ATRANSACTIONSTRING ( Z_PK INTEGER PRIMARY KEY, Z_ENT INTEGER, Z_OPT INTEGER, ZNAME VARCHAR );
CREATE TABLE ZMAINTENANCELOG ( Z_PK INTEGER PRIMARY KEY, Z_ENT INTEGER, Z_OPT INTEGER, ZMILEAGE INTEGER, ZCAR INTEGER, ZCOST FLOAT, ZDATE TIMESTAMP, ZITEMIDSRAW VARCHAR, ZNOTE VARCHAR, ZID BLOB , ZCYCLEKEY VARCHAR);
CREATE TABLE ZMAINTENANCELOGITEM ( Z_PK INTEGER PRIMARY KEY, Z_ENT INTEGER, Z_OPT INTEGER, ZLOG INTEGER, ZCREATEDAT TIMESTAMP, ZCYCLEITEMKEY VARCHAR, ZID BLOB, ZITEMID BLOB );
CREATE TABLE Z_PRIMARYKEY (Z_ENT INTEGER PRIMARY KEY, Z_NAME VARCHAR, Z_SUPER INTEGER, Z_MAX INTEGER);
CREATE UNIQUE INDEX Z_Car_UNIQUE_id ON ZCAR (ZID COLLATE BINARY ASC);
CREATE INDEX ZFUELLOG_ZCAR_INDEX ON ZFUELLOG (ZCAR);
CREATE UNIQUE INDEX Z_FuelLog_UNIQUE_id ON ZFUELLOG (ZID COLLATE BINARY ASC);
CREATE UNIQUE INDEX Z_MaintenanceItemOption_UNIQUE_id ON ZMAINTENANCEITEMOPTION (ZID COLLATE BINARY ASC);
CREATE UNIQUE INDEX Z_MaintenanceItemOption_UNIQUE_name ON ZMAINTENANCEITEMOPTION (ZNAME COLLATE BINARY ASC);
CREATE INDEX ACHANGE_ZTRANSACTIONID_INDEX ON ACHANGE (ZTRANSACTIONID);
CREATE INDEX ATRANSACTION_ZAUTHORTS_INDEX ON ATRANSACTION (ZAUTHORTS);
CREATE INDEX ATRANSACTION_ZBUNDLEIDTS_INDEX ON ATRANSACTION (ZBUNDLEIDTS);
CREATE INDEX ATRANSACTION_ZCONTEXTNAMETS_INDEX ON ATRANSACTION (ZCONTEXTNAMETS);
CREATE INDEX ATRANSACTION_ZPROCESSIDTS_INDEX ON ATRANSACTION (ZPROCESSIDTS);
CREATE INDEX Z_TRANSACTION_TransactionAuthorIndex ON ATRANSACTION (ZAUTHOR COLLATE BINARY ASC);
CREATE INDEX Z_TRANSACTION_TransactionTimestampIndex ON ATRANSACTION (ZTIMESTAMP COLLATE BINARY ASC);
CREATE UNIQUE INDEX Z_TRANSACTIONSTRING_UNIQUE_NAME ON ATRANSACTIONSTRING (ZNAME COLLATE BINARY ASC);
CREATE INDEX ZMAINTENANCELOG_ZCAR_INDEX ON ZMAINTENANCELOG (ZCAR);
CREATE UNIQUE INDEX Z_MaintenanceLog_UNIQUE_id ON ZMAINTENANCELOG (ZID COLLATE BINARY ASC);
CREATE UNIQUE INDEX Z_MaintenanceLog_UNIQUE_cycleKey ON ZMAINTENANCELOG (ZCYCLEKEY COLLATE BINARY ASC);
CREATE INDEX ZMAINTENANCELOGITEM_ZLOG_INDEX ON ZMAINTENANCELOGITEM (ZLOG);
CREATE UNIQUE INDEX Z_MaintenanceLogItem_UNIQUE_id ON ZMAINTENANCELOGITEM (ZID COLLATE BINARY ASC);
CREATE UNIQUE INDEX Z_MaintenanceLogItem_UNIQUE_cycleItemKey ON ZMAINTENANCELOGITEM (ZCYCLEITEMKEY COLLATE BINARY ASC);
COMMIT;
